css:
table {
    margin: 0 auto; /* or margin: 0 auto 0 auto */
    width: 100%;
  }
  
#table {
   font-family: Arial, Helvetica, sans-serif;
   border-collapse: collapse;
   width: 100%;
    
}

#table td, #table th {
  border: 1px solid #89CFF0;
  padding: 2px;
  padding-top: 2px;
  padding-bottom: 2px;
}

#table tr:nth-child(even){background-color: #f2f2f2;}

#table tr:hover {background-color: #ddd;}

#table th {
  padding-top: 2px;
  padding-bottom: 2px;
  text-align: left;
  background-color: #dce4e6;
  color: white;
}
  
  
  


#main {
   margin-left: 20px;
   margin-right: 20px;
}

@media all {
   div .printedby {
       position: absolute;
       bottom: 30px;
       left: 0;
       text-align: center;
       font-size: xx-small;
       width: 100% !important;
       height: 20px !important;
   }
}
   div .terms {
	font-size: 20%;
   }

#lastPara { margin-bottom: 0; padding-bottom: 0; }
